index 53632efe913e..5afc9a1d6871 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -14507,6 +14507,17 @@ Value *BoUpSLP::vectorizeTree(TreeEntry *E, bool PostponedPHIs) {
   Instruction *VL0 = E->getMainOp();
   auto GetOperandSignedness = [&](unsigned Idx) {
     const TreeEntry *OpE = getOperandEntry(E, Idx);
+    // Booleans (i1) are 0/1 and must be treated as unsigned when widened.
+    // If all operand scalars are i1 (or vectors of i1), force unsigned.
+    auto IsI1Type = [](Type *Ty) {
+      if (Ty->isIntegerTy(1))
+        return true;
+      if (auto *VTy = dyn_cast<VectorType>(Ty))
+        return VTy->getElementType()->isIntegerTy(1);
+      return false;
+    };
+    if (all_of(OpE->Scalars, [&](Value *R) { return IsI1Type(R->getType()); }))
+      return false;
     bool IsSigned = false;
     auto It = MinBWs.find(OpE);
     if (It != MinBWs.end())
@@ -14802,6 +14813,9 @@ Value *BoUpSLP::vectorizeTree(TreeEntry *E, bool PostponedPHIs) {
           VecOpcode = Instruction::BitCast;
         } else if (BWSz < SrcBWSz) {
           VecOpcode = Instruction::Trunc;
+        } else if (SrcScalarTy->getScalarType()->isIntegerTy(1)) {
+          // Widening from i1 must always use zero-extension.
+          VecOpcode = Instruction::ZExt;
         } else if (It != MinBWs.end()) {
           assert(BWSz > SrcBWSz && "Invalid cast!");
           VecOpcode = It->second.second ? Instruction::SExt : Instruction::ZExt;
@@ -14849,10 +14863,22 @@ Value *BoUpSLP::vectorizeTree(TreeEntry *E, bool PostponedPHIs) {
                                              ->getElementType()
                                              ->getIntegerBitWidth()) {
           Type *CastTy = R->getType();
-          L = Builder.CreateIntCast(L, CastTy, GetOperandSignedness(0));
+          // If casting from i1 to a wider integer type, force zero-extension.
+          auto *LEltTy = cast<VectorType>(L->getType())->getElementType();
+          if (LEltTy->isIntegerTy(1) && cast<VectorType>(CastTy)->getElementType()->isIntegerTy()) {
+            L = Builder.CreateZExt(L, CastTy);
+          } else {
+            L = Builder.CreateIntCast(L, CastTy, GetOperandSignedness(0));
+          }
         } else {
           Type *CastTy = L->getType();
-          R = Builder.CreateIntCast(R, CastTy, GetOperandSignedness(1));
+          // If casting from i1 to a wider integer type, force zero-extension.
+          auto *REltTy = cast<VectorType>(R->getType())->getElementType();
+          if (REltTy->isIntegerTy(1) && cast<VectorType>(CastTy)->getElementType()->isIntegerTy()) {
+            R = Builder.CreateZExt(R, CastTy);
+          } else {
+            R = Builder.CreateIntCast(R, CastTy, GetOperandSignedness(1));
+          }
         }
       }

@@ -14953,6 +14979,20 @@ Value *BoUpSLP::vectorizeTree(TreeEntry *E, bool PostponedPHIs) {
         return E->VectorizedValue;
       }

+      // Preserve the original freeze result type. If the scalar freeze produces
+      // a wider integer type (e.g., freezing after zext i1->i8), ensure we cast
+      // the operand to that type before freezing. Booleans must be zero-extended.
+      Type *FreezeScalarTy = cast<FreezeInst>(VL0)->getType();
+      auto *OpVTy = cast<VectorType>(Op->getType());
+      auto *DesiredVecTy = VectorType::get(FreezeScalarTy, OpVTy->getElementCount());
+      if (Op->getType() != DesiredVecTy) {
+        auto *InEltTy = OpVTy->getElementType();
+        bool IsSigned = false;
+        if (!InEltTy->isIntegerTy(1))
+          IsSigned = GetOperandSignedness(0);
+        Op = Builder.CreateIntCast(Op, DesiredVecTy, IsSigned);
+      }
+
       Value *V = Builder.CreateFreeze(Op);
       V = FinalShuffle(V, E);

reason_thou:
1. Understanding the Issue:
The produced vectorized IR differs semantically from the source for the given test. Specifically, the target performs a sign extension (sext) from a vector of i1 to a vector of i8 after freezing the i1 vector, while the source semantics require a zero extension (zext) from i1 to i8. This changes true from 1 to -1 (0xFF), which then affects the unsigned comparison (ugt) and cascading selects/subtractions, leading to the incorrect final reduction result.

2. Analyzing opt's Log:
- The SLP pass recognized and vectorized a horizontal reduction and several bundles. The key generated target sequence:
  %6 = freeze <4 x i1> %3
  %7 = sext <4 x i1> %6 to <4 x i8>
  %10 = icmp ugt <4 x i8> %7, %9
- In the scalar source, the sequence is: zext i1 -> i8, freeze i8, compare ugt. The target performs freeze on the i1 vector and then casts to i8 during type reconciliation inside the ICmp vectorization path.
- The point where the cast choice is made is in vectorizeTree under the ICmp case (lines ~14840-14856): when L and R types differ, Builder.CreateIntCast is called with GetOperandSignedness(Idx). If that returns true, it will sign-extend (sext); otherwise, zero-extend (zext).
- The log shows the erroneous sext, implying GetOperandSignedness determined the operand as signed, even though i1 values used as boolean masks are non-negative and should be extended as unsigned.

3. Root Cause Analysis:
The lambda GetOperandSignedness (around lines 14509-14519) determines signedness using MinBWs or by checking if any scalar operand is not known non-negative via isKnownNonNegative. For i1 values, especially those feeding boolean casts/selects/comparisons, the correct behavior is to treat them as unsigned (0 or 1), regardless of isKnownNonNegative proof. However, the current heuristic can return true (signed) when non-negativity cannot be proven, leading to sext from i1 to wider integer types. This is incorrect for boolean vectors in comparisons/selects and results in semantic mismatches as demonstrated.
Therefore, we must special-case i1 types: if the operand entry corresponds to values of i1 (or vectors of i1), signedness should be false (unsigned), guaranteeing zext when widening.

4. Proposed Edit Point(s)
- File: llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
- Location: In BoUpSLP::vectorizeTree, within the lambda GetOperandSignedness defined around lines 14509-14519.
- Change: Add an early check to force unsigned for boolean types. Pseudocode:
  auto GetOperandSignedness = [&](unsigned Idx) {
    const TreeEntry *OpE = getOperandEntry(E, Idx);
    // New: If all operand scalars are i1 (or the operand vector element type is i1), treat as unsigned.
    bool AllI1 = all_of(OpE->Scalars, [](Value *R){
      Type *Ty = R->getType();
      return Ty->isIntegerTy(1) || (isa<VectorType>(Ty) && cast<VectorType>(Ty)->getElementType()->isIntegerTy(1));
    });
    if (AllI1)
      return false;
    bool IsSigned = false;
    auto It = MinBWs.find(OpE);
    if (It != MinBWs.end())
      IsSigned = It->second.second;
    else
      IsSigned = any_of(OpE->Scalars, [&](Value *R) {
        return !isKnownNonNegative(R, SimplifyQuery(*DL));
      });
    return IsSigned;
  };
This ensures widening casts on boolean predicates use zext, matching scalar semantics.

5. Conclusion:
The mismatch originates from choosing sign-extension when widening boolean vectors to i8 within the ICmp vectorization path. By forcing unsigned widening for i1 operands in GetOperandSignedness, the vectorized IR will use zext instead of sext, aligning with the scalar source behavior and fixing the Alive2 discrepancy. This change is localized and consistent with LLVM's convention of treating booleans as 0/1 non-negative values when casting to larger integer types.

